function doRedo(){if(!redo.length)return msg('ไม่มีรายการให้ Redo');undo.push(snap());restore(redo.pop());render();msg('Redo แล้ว')}
function pk(r){return[r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|')}
