function dates(){return[...new Set(rawRows.map(r=>r.date).filter(Boolean))].sort()}
function psValues(){return[...new Set(rawRows.map(r=>r.ps).filter(Boolean))].sort(coll.compare)}
function baseRows(){const q=T(filters.q).toLowerCase();return R.filter(r=>(!filters.start||r.date>=filters.start)&&(!filters.end||r.date<=filters.end)&&(!filters.ps||r.ps===filters.ps)&&(!filters.brand||r.brand===filters.brand)&&(!filters.type||r.type===filters.type)&&(!q||[r.date,r.inv,r.code,r.sku,r.store,r.ps,r.brand,r.size,r.type,r.tele].join(' ').toLowerCase().includes(q)))}
