function group(rows,byStore=false){const m=new Map();rows.forEach(r=>{const p=pk(r),k=byStore?[r.store,p].join('|'):p;let x=m.get(k);if(!x){x={poolKey:p,store:byStore?r.store:'',brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,qty:0,amt:0,unit:r.unit||0,bills:new Set(),stores:new Map()};m.set(k,x)}x.qty+=N(r.qty);x.amt+=N(r.amt);x.unit=x.qty&&x.amt?x.amt/x.qty:x.unit;x.bills.add(r.inv);x.stores.set(r.store,(x.stores.get(r.store)||0)+N(r.qty))});return[...m.values()].sort((a,b)=>(a.store||'').localeCompare(b.store||'','th')||coll.compare(a.brand,b.brand)||coll.compare(a.size,b.size)||coll.compare(a.sku,b.sku))}
function addScoped(out,pk,v){out.set(pk,(out.get(pk)||0)+N(v))}
function rebuildScoped(){const head=scopeHead();scoped={send:new Map(),add:new Map(),pull:new Map(),sent:0,addTotal:0,pullTotal:0};Object.entries(send).forEach(([k,v])=>{if(k.startsWith(head)){const n=N(v);scoped.sent+=n;addScoped(scoped.send,pkFromKey(k),n)}});Object.entries(add).forEach(([k,v])=>{if(k.startsWith(head)){const n=N(v);scoped.addTotal+=n;addScoped(scoped.add,pkFromKey(k),n)}});Object.entries(pull).forEach(([k,v])=>{if(k.startsWith(head)){const n=N(v);scoped.pullTotal+=n;addScoped(scoped.pull,pkFromKey(k),n)}})}
function smap(m,pk){return N((m instanceof Map?m:scoped[m])?.get(pk))}
