function recvVal(map,g){return receiver?N(map[rkey(g.poolKey)]):0}
function realTele(r){const a=T(r.tele).toLowerCase(),b=T(r.ps).toLowerCase();return !!a&&!(a===b||a.includes(b)||b.includes(a))}
